# Map file created from QGIS project file C:/Program Files (x86)/Quantum GIS Wroclaw/qqq.qgs
# Edit this file to customize for your map interface
# (Created with PyQgis MapServer Export plugin)
MAP
	SYMBOLSET "symbols\\symbols.sym"
	CONFIG "PROJ_LIB" "conf"
	NAME "QGIS-MAP"
	FONTSET "fonts/fonts.list"
	# Map image size  
	SIZE 100 100
	UNITS meters
  
	#EXTENT 72.504366 18.900959 73.403214 19.320367
	PROJECTION
		'proj=longlat'
		'datum=WGS84'
		'no_defs'
	END

	# Background color for the map canvas -- change as desired
	IMAGECOLOR 255 255 255
	IMAGEQUALITY 95
	IMAGETYPE png

	OUTPUTFORMAT
		NAME png
		DRIVER 'GD/PNG'
		MIMETYPE 'image/png'
		IMAGEMODE RGBA
		EXTENSION 'png'
	END
  
	# Legend
	LEGEND
		IMAGECOLOR 255 255 255
		STATUS ON
		KEYSIZE 25 15
		LABEL
		  TYPE BITMAP	  
		  SIZE MEDIUM
		  COLOR 0 0 89
		END		
	END
  
	SYMBOL
		NAME "circlef"
		TYPE ellipse
		FILLED true
		POINTS 
			1 1
		END
	END	
	SYMBOL
		NAME "arrow-end"
		TYPE vector
		FILLED false
		POINTS
			0  10
			10  5
			0 0
		END
		#ANCHORPOINT 1 0.5
	END 


	# Web interface definition. Only the template parameter
	# is required to display a map. See MapServer documentation
	WEB
		# Set IMAGEPATH to the path where MapServer should
		# write its output.
		IMAGEPATH '/tmp/'

		# Set IMAGEURL to the url that points to IMAGEPATH
		# as defined in your web server configuration
		IMAGEURL '/tmp/'
	# WMS server settings
	METADATA
		'ows_title'           'QGIS-MAP'
		#'ows_onlineresource'  ''
		'ows_srs'             'EPSG:4326 EPSG:900913' 
		'ows_enable_request'   '*'
	END

	#Scale range at which web interface will operate
	# Template and header/footer settings
	# Only the template parameter is required to display a map. See MapServer documentation
	TEMPLATE 'fooOnlyForWMSGetFeatureInfo'
	END

	#SYMBOL
	 	#NAME "rail"
	 	# TYPE PIXMAP		
	  	#IMAGE "icons/railway.png"		
	#END	
#=================REGION=====================================	
	LAYER		
		NAME 'REG' 
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%regionFilter%"
		DATA 'sp_geometry FROM "vw_region_boundary_map" USING UNIQUE region_id USING srid=4326'
		FILTER  (%regionFilter% )
		VALIDATION		
			'regionFilter'   '.*'				
		END
		METADATA
			'ows_title' 'Region'
		END
		STATUS OFF	
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'Region' 
			STYLE
				WIDTH 3
				OUTLINECOLOR 255 0 0
				COLOR -1 -1 -1
			END
		END
	END
# ========== PROVINCE================================= 
	LAYER 
		NAME 'PRO'
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%provinceFilter%"
		DATA 'sp_geometry FROM "vw_province_boundary_map" USING UNIQUE province_id USING srid=4326'
		FILTER  (%provinceFilter% )
		VALIDATION		
			'provinceFilter'   '.*'				
		END   
		METADATA
			'ows_title' 'Province'
		END
		STATUS OFF	
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'Province' 
			STYLE
				WIDTH 2
				OUTLINECOLOR 0 0 255
				COLOR -1 -1 -1
			END
		END
	END







	

