			'layerFilter'   '.*'
		END 
		METADATA
			'ows_title' 'SPLITTER'
		END
		STATUS OFF
		GROUP 'Network'		
		CLASS
			NAME 'Primary Splitter'
            EXPRESSION ('[splitter_type]'  eq 'Primary')  			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END
            LABEL
				COLOR  255 0 0 
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END				
		END
        CLASS
			NAME 'Secondary Splitter' 
			EXPRESSION ('[splitter_type]'  eq 'Secondary')  
			STYLE
				SYMBOL [icon_path]
				SIZE 18        
			END
			LABEL
				COLOR  255 0 0 
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END	
		END			
	END	
