# ===================BUILDING (APPROVED CENTROID POINT)======================================================= 
	LAYER
		NAME 'BLDC'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo		
		INCLUDE "datashare.inc"
		DATA 'sp_centroid FROM vw_att_details_building_MAP USING UNIQUE system_id USING srid=4326'	
	    FILTER (%provinceFilter% )
		FILTER (%layerFilter% )
		VALIDATION		
			'provinceFilter'   '.*'	
            'layerFilter'   '.*'			
		END 
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF
		GROUP 'Network'	
		
		CLASS
			
			NAME 'N-RFS Residential High Rise'
			EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && (('[category]' eq 'Residential') && ( [home_pass] >= 10)))
			STYLE
				SYMBOL "icons/N-RFSResidentialHighRise.png"
				SIZE 18    
			END
		END	


		CLASS
		
			NAME 'N-RFS Residential Low Rise'
			EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && (('[category]' eq 'Residential') && ([home_pass] < 10)))
			STYLE
				SYMBOL "icons/N-RFSResidentialLowRise.png"
				SIZE 18        
			END
		END	
		
		CLASS
			
			NAME 'N-RFS Commercial High Rise'
			EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && (('[category]' eq 'Commercial') && ([business_pass] >= 10)))
			STYLE
				SYMBOL "icons/N-RFSCommercialHighRise.png"
				SIZE 18        
			END
		END	
		
		CLASS
			
			NAME 'N-RFS Commercial Low Rise'
			EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && (('[category]' eq 'Commercial') && ([business_pass] < 10)))
			STYLE
				SYMBOL "icons/N-RFSCommercialLowRise.png"
				SIZE 18        
			END
		END	
		
		
		CLASS
			
			NAME 'N-RFS Commercial and Residential'
			EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && ('[category]' eq 'Both'))
			STYLE
				SYMBOL "icons/N-RFSCommercialResidential.png"
				SIZE 18        
			END
		END	
		
		CLASS
			
			NAME 'RFS Residential High Rise'
			EXPRESSION ((('[rfs_status]' != 'Non-RFS') OR ('[rfs_status]' != 'N-RFS')) && (('[category]' eq 'Residential') && ( [home_pass] >= 10)))
			STYLE
				SYMBOL "icons/RFSResidentialHighRise.png"
				SIZE 18    
			END
		END
		
        CLASS
			
			NAME 'RFS Residential Low Rise'
			EXPRESSION ((('[rfs_status]' != 'Non-RFS') OR ('[rfs_status]' != 'N-RFS')) && (('[category]' eq 'Residential') && ( [home_pass] < 10)))
			STYLE
				SYMBOL "icons/RFSResidentialLowRise.png"
				SIZE 18    
			END
		END	
		CLASS
			
			NAME 'RFS Commercial High Rise'
			EXPRESSION ((('[rfs_status]' != 'Non-RFS') OR ('[rfs_status]' != 'N-RFS')) && (('[category]' eq 'Commercial') && ([business_pass] >= 10)))
			STYLE
				SYMBOL "icons/RFSCommercialHighRise.png"
				SIZE 18        
			END
		END	
		CLASS
			
			NAME 'RFS Commercial Low Rise'
			EXPRESSION ((('[rfs_status]' != 'Non-RFS') OR ('[rfs_status]' != 'N-RFS')) && (('[category]' eq 'Commercial') && ([business_pass] < 10)))
			STYLE
				SYMBOL "icons/RFSCommercialLowRise.png"
				SIZE 18        
			END
		END
		CLASS
			
			NAME 'RFS Commercial and Residential'
			EXPRESSION ((('[rfs_status]' != 'Non-RFS') OR ('[rfs_status]' != 'N-RFS')) && ('[category]' eq 'Both'))
			STYLE
				SYMBOL "icons/RFSCommercialResidential.png"
				SIZE 18        
			END
		END

		
