		# ===================SUB AREA======================================= 	
	LAYER 
		NAME 'SBA'
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%provinceFilter%"
		DATA 'sp_geometry FROM "vw_att_details_subarea_map" USING UNIQUE system_id USING srid=4326'
		FILTER  (%provinceFilter%)	
        FILTER  (%layerFilter% )		
		VALIDATION		
			'provinceFilter'   '.*'	
            'layerFilter'   '.*' 			
		END 
		METADATA
			'ows_title' 'SubArea'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'SubArea' 
			STYLE
				WIDTH 1
				OUTLINECOLOR 0 0 0
				COLOR [color_code] 
			END
		END
	END

